"use client";

/* ════════════════════════════════════════════════════════════════════════
   Study · Library — what you've made (study spec §4.3).
   Split shell: navy "talk to your library" companion (left) + parchment
   Library room (right) — a filterable grid of white artifact cards with
   status, provenance ("From [conversation]"), and performance. Ported from
   magellan-study-4-library.html. Currency = USD ($).
   ════════════════════════════════════════════════════════════════════════ */

import { useState } from "react";
import { useRouter } from "next/navigation";
import "./StudyLibrary.css";

const RAIL_W = 96;

const TYPE_FILTERS = [
  { label: "All", count: "147" },
  { label: "Emails", count: "62" },
  { label: "Ad copy", count: "28" },
  { label: "Product copy", count: "34" },
  { label: "Memos", count: "23" },
];
const SORTS = ["Recent", "Needs action", "Performance"];

export function StudyLibrary() {
  const [folded, setFolded] = useState(false);
  const [convoW, setConvoW] = useState(400);
  const [dragging, setDragging] = useState(false);
  const [activeType, setActiveType] = useState(0);
  const [activeSort, setActiveSort] = useState(0);
  const [draft, setDraft] = useState("");
  const [extra, setExtra] = useState<Array<{ role: "you" | "mag"; text: string }>>([]);
  const router = useRouter();
  // Clicking any artifact card opens it in Build (study spec §4.3).
  const openArtifact = () => router.push("/study/build");

  const clamp = (v: number) => {
    const max = Math.min(typeof window !== "undefined" ? window.innerWidth * 0.55 : 640, 640);
    return Math.max(320, Math.min(max, v));
  };
  const sendAsk = () => {
    const text = draft.trim();
    if (!text) return;
    setExtra((m) => [...m, { role: "you", text }]);
    setDraft("");
    setTimeout(() => setExtra((m) => [...m, { role: "mag", text: "On it — I've filtered the library to match." }]), 800);
  };

  return (
    <div
      className={`study-library${folded ? " folded" : ""}`}
      style={{ ["--convo-w" as string]: `${convoW}px` } as React.CSSProperties}
    >
      {/* ── LEFT — talk to your library ── */}
      <aside className="convo">
        <div className="convo-head">
          <div className="ch-avatar">M</div>
          <div className="ch-id">
            <div className="ch-name">Magellan</div>
            <div className="ch-scope"><span className="dot" />Library · 147 artifacts</div>
          </div>
          <button className="ch-fold" title="Browse full width" type="button" onClick={() => setFolded(true)}>
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><polyline points="15 18 9 12 15 6" /></svg>
          </button>
        </div>
        <div className="convo-body">
          <div className="day">Today · 10:31 AM</div>
          <div className="msg-you">What&rsquo;s ready to ship that I haven&rsquo;t sent yet?<span className="t">10:31</span></div>
          <div className="msg-mag">
            <div className="who">Magellan · 10:31</div>
            <div className="body">
              Eight are ready and waiting on you. I&rsquo;ve filtered the library to those and sorted by what&rsquo;s most time-sensitive — the <span className="warn">Valentine&rsquo;s reactivation window closes in 2 days</span>.
              <div className="find-sum">
                <div className="fs-row"><span className="n">3</span><span className="lab">Emails</span><span className="tag">Ready</span></div>
                <div className="fs-row"><span className="n">4</span><span className="lab">Ad sets</span><span className="tag">Ready</span></div>
                <div className="fs-row"><span className="n">1</span><span className="lab">Product page</span><span className="tag">Ready</span></div>
              </div>
            </div>
          </div>
          <div className="msg-you">Which email performed best last quarter?<span className="t">10:33</span></div>
          <div className="msg-mag">
            <div className="who">Magellan · 10:33</div>
            <div className="body">The <span className="good">Valentine&rsquo;s reactivation</span> — 34% open, <span className="good">$42K</span> in attributed revenue from a lapsed segment. Want me to remix it for Mother&rsquo;s Day, or build something new?</div>
          </div>
          {extra.map((m, i) =>
            m.role === "you" ? (
              <div key={i} className="msg-you">{m.text}</div>
            ) : (
              <div key={i} className="msg-mag"><div className="who">Magellan</div><div className="body">{m.text}</div></div>
            )
          )}
        </div>
        <div className="convo-composer">
          <div className="cc-foot"><span className="dot" />Scoped to Library</div>
          <div className="cc-wrap">
            <input
              className="cc-input"
              placeholder="Find, compare, or remix anything you&rsquo;ve made…"
              value={draft}
              onChange={(e) => setDraft(e.target.value)}
              onKeyDown={(e) => { if (e.key === "Enter") { e.preventDefault(); sendAsk(); } }}
            />
            <div className="cc-row">
              <button className="cc-btn" title="Attach" type="button">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48" /></svg>
              </button>
              <span className="cc-spacer" />
              <button className="cc-mic" title="Hold to talk" type="button">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M12 1a3 3 0 00-3 3v8a3 3 0 006 0V4a3 3 0 00-3-3z" /><path d="M19 10v2a7 7 0 01-14 0v-2" /><line x1="12" y1="19" x2="12" y2="23" /><line x1="8" y1="23" x2="16" y2="23" /></svg>
              </button>
              <button className="cc-send" title="Send" type="button" onClick={sendAsk}>
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><line x1="12" y1="19" x2="12" y2="5" /><polyline points="5 12 12 5 19 12" /></svg>
              </button>
            </div>
          </div>
        </div>
      </aside>

      <div
        className={`resizer${dragging ? " dragging" : ""}`}
        title="Drag to resize · double-click to reset"
        onPointerDown={(e) => { setDragging(true); e.currentTarget.setPointerCapture(e.pointerId); }}
        onPointerMove={(e) => { if (dragging) setConvoW(clamp(e.clientX - RAIL_W)); }}
        onPointerUp={(e) => { setDragging(false); e.currentTarget.releasePointerCapture(e.pointerId); }}
        onDoubleClick={() => setConvoW(400)}
      >
        <div className="resizer-grip" />
      </div>
      <button className="unfold" title="Show Magellan" type="button" onClick={() => setFolded(false)}>
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><polyline points="9 18 15 12 9 6" /></svg>
      </button>

      {/* ── RIGHT — the Library room ── */}
      <main className="work">
        <div className="lib-head">
          <div className="lh-top">
            <div>
              <div className="lh-title">Library</div>
              <div className="lh-sub">147 artifacts · <b>8 ready to ship</b></div>
            </div>
            <div className="lh-spacer" />
            <div className="lib-search">
              <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><circle cx="11" cy="11" r="7" /><line x1="21" y1="21" x2="16.65" y2="16.65" /></svg>
              <input placeholder="Search the library…" />
              <span className="kbd">⌘K</span>
            </div>
          </div>
          <div className="lib-filters">
            {TYPE_FILTERS.map((f, i) => (
              <button key={f.label} className={`fchip${i === activeType ? " active" : ""}`} type="button" onClick={() => setActiveType(i)}>
                {f.label} <span className="ct">{f.count}</span>
              </button>
            ))}
            <div className="fsort">
              <span className="fsort-lab">Sort</span>
              {SORTS.map((s, i) => (
                <button key={s} className={`fsort-btn${i === activeSort ? " active" : ""}`} type="button" onClick={() => setActiveSort(i)}>{s}</button>
              ))}
            </div>
          </div>
        </div>

        <div className="lib-body">
          <div className="date-group">
            <div className="date-label">Today</div>
            <div className="grid">
              <button className="card" type="button" onClick={openArtifact}>
                <div className="thumb t-email">
                  <div className="tk">For Mother&rsquo;s Day · May 11</div>
                  <div className="tt">Hello, again.</div>
                  <div className="tr" />
                  <div className="tl w1" /><div className="tl w2" />
                </div>
                <div className="lc-body">
                  <div className="lc-top"><span className="lc-type">Email</span><span className="lc-status review"><span className="d" />Awaiting review</span></div>
                  <div className="lc-title">Three Mother&rsquo;s Days in a row — and counting</div>
                  <div className="lc-from">From <a>Why Mother&rsquo;s Day underperformed</a></div>
                  <div className="lc-meta">Draft · edited today<span className="sep" />2,847 recipients</div>
                </div>
              </button>

              <button className="card" type="button" onClick={openArtifact}>
                <div className="thumb t-ad">
                  <div className="ak">Meta · Lookalike 1%</div>
                  <div className="at">Some things deserve to become tradition.</div>
                  <div className="acta">Shop now</div>
                </div>
                <div className="lc-body">
                  <div className="lc-top"><span className="lc-type">Ad copy</span><span className="lc-status ready"><span className="d" />Ready</span></div>
                  <div className="lc-title">Spring lookalike test — 3 variants</div>
                  <div className="lc-from">From <a>Meta ad fatigue analysis</a></div>
                  <div className="lc-meta">$15K budget queued<span className="sep" />Static · Carousel · Reel</div>
                </div>
              </button>

              <button className="card" type="button" onClick={openArtifact}>
                <div className="thumb t-memo">
                  <div className="ml h" />
                  <div className="ml w1" /><div className="ml w2" /><div className="ml w1" /><div className="ml w3" />
                </div>
                <div className="lc-body">
                  <div className="lc-top"><span className="lc-type">Memo</span><span className="lc-status saved"><span className="d" />Saved to memory</span></div>
                  <div className="lc-title">Premium positioning vs. volume — the case against discounting</div>
                  <div className="lc-from">From <a>Pricing philosophy</a></div>
                  <div className="lc-meta">1,840 words<span className="sep" />referenced 6×</div>
                </div>
              </button>
            </div>
          </div>

          <div className="date-group">
            <div className="date-label">Earlier this quarter</div>
            <div className="grid">
              <button className="card" type="button" onClick={openArtifact}>
                <div className="thumb t-email">
                  <div className="tk">A little overdue · Feb 12</div>
                  <div className="tt">We saved you a seat.</div>
                  <div className="tr" />
                  <div className="tl w1" /><div className="tl w2" />
                </div>
                <div className="lc-body">
                  <div className="lc-top"><span className="lc-type">Email</span><span className="lc-status live"><span className="d" />Sent &amp; live</span></div>
                  <div className="lc-title">Valentine&rsquo;s reactivation — lapsed VIP segment</div>
                  <div className="lc-from">From <a>Win-back strategy</a></div>
                  <div className="lc-meta"><span className="perf">34% open · $42K</span><span className="sep" />Sent Feb 12</div>
                </div>
              </button>

              <button className="card" type="button" onClick={openArtifact}>
                <div className="thumb t-product">
                  <div className="pimg" />
                  <div className="pmeta"><div className="pn">Orange Hazelnut Dacquoise</div><div className="pp">$1,490 – $3,290</div></div>
                </div>
                <div className="lc-body">
                  <div className="lc-top"><span className="lc-type">Product copy</span><span className="lc-status live"><span className="d" />Live</span></div>
                  <div className="lc-title">Orange Hazelnut Dacquoise — page &amp; descriptions</div>
                  <div className="lc-from">From <a>New cake launch</a></div>
                  <div className="lc-meta"><span className="perf">2.1% CVR</span><span className="sep" />live since Apr</div>
                </div>
              </button>

              <button className="card" type="button" onClick={openArtifact}>
                <div className="thumb t-ad choc">
                  <div className="ak">Meta · Reels</div>
                  <div className="at">Dangerously good.</div>
                  <div className="acta">Order today</div>
                </div>
                <div className="lc-body">
                  <div className="lc-top"><span className="lc-type">Ad copy</span><span className="lc-status draft"><span className="d" />Drafting</span></div>
                  <div className="lc-title">Devil&rsquo;s Chocolate Cake — Reels campaign</div>
                  <div className="lc-from">From <a>Q2 cake campaign</a></div>
                  <div className="lc-meta">2 variants<span className="sep" />needs Thai review</div>
                </div>
              </button>

              <button className="card" type="button" onClick={openArtifact}>
                <div className="thumb t-email">
                  <div className="tk">Welcome to UrbanFlowers</div>
                  <div className="tt">Let&rsquo;s begin.</div>
                  <div className="tr" />
                  <div className="tl w1" /><div className="tl w2" />
                </div>
                <div className="lc-body">
                  <div className="lc-top"><span className="lc-type">Email</span><span className="lc-status ready"><span className="d" />Ready</span></div>
                  <div className="lc-title">Welcome flow v2 — refreshed subject line</div>
                  <div className="lc-from">From <a>Welcome flow open rate dropped 8%</a></div>
                  <div className="lc-meta">replaces current welcome<span className="sep" />3-email sequence</div>
                </div>
              </button>
            </div>
          </div>
        </div>
      </main>
    </div>
  );
}
